lessons.starter:
type Command = { kind: "add"; left: number; right: number } | { kind: "divide"; left: number; right: number };
function parse(input: string): Command {
  const [kind, leftText = "", rightText = ""] = input.split(/\s+/);
  // TODO: validate complete finite numeric tokens and reject zero division.
  const left = Number.parseInt(leftText, 10);
  const right = Number.parseInt(rightText, 10);
  return kind === "divide" ? { kind, left, right } : { kind: "add", left, right };
}
async function execute(command: Command): Promise<number> {
  return command.kind === "add" ? command.left + command.right : command.left / command.right;
}
async function main(): Promise<void> {
  const raw = require("node:fs").readFileSync(0, "utf8").trim();
  process.stdout.write(`${await execute(parse(raw))}\n`);
}
main().catch((error: unknown) => process.stdout.write(`${error instanceof Error ? "invalid" : "unknown"}\n`));
